var UserConnection = Get<UserConnection>("UserConnection");
var SubmissionId = Get<Guid>("SubmissionId");
var LineDetailId = Get<Guid>("LineDetailId");
var xml = Get<string>("XML");
var SONumber = Get<string>("SONumber");

try {
	var service = new MMAGOrderCreateService(UserConnection);
	var successRes = new Dictionary<string, bool>();

	if(!string.IsNullOrEmpty(xml) && string.IsNullOrEmpty(SONumber) && SubmissionId == Guid.Empty && LineDetailId == Guid.Empty) {
		
		service.SetParam(xml);
		Set("Request", service.GetStringRequest());
		
		service.Request().GetAwaiter().GetResult();
		if(!service.IsSuccessResponse()) {
			throw new Exception(service.GetErrorResponse());
		}

		Set("Response", service.GetStringResponse());
		return true;
		
	} else if(string.IsNullOrEmpty(xml) && !string.IsNullOrEmpty(SONumber) && SubmissionId != Guid.Empty && LineDetailId == Guid.Empty) {
		
		service.SetParamBySONumber("SONumber");
		
	} else if(string.IsNullOrEmpty(xml) && string.IsNullOrEmpty(SONumber) && SubmissionId != Guid.Empty && LineDetailId == Guid.Empty) {
		
		service.SetParamBySubmission(SubmissionId);
		
	} else if(string.IsNullOrEmpty(xml) && string.IsNullOrEmpty(SONumber) && SubmissionId == Guid.Empty && LineDetailId != Guid.Empty) {
		
		service.SetParamByLineDetail(LineDetailId);

	} else { 
		throw new Exception("Input param harus diisi salah satunya");
	}

	Set("Request", service.GetStringRequest());

	service.Request().GetAwaiter().GetResult();
	if(!service.IsSuccessResponse()) {
		throw new Exception(service.GetErrorResponse());
	}

	Set("Response", service.GetStringResponse());

} catch(Exception e) {
	Set("Message", e.Message);
}

return true;
